function diff(oldNode, newNode) {
  if (!oldNode) return { type: 'CREATE', newNode };
  if (!newNode) return { type: 'REMOVE' };
  if (oldNode.tag !== newNode.tag) return { type: 'REPLACE', newNode };
  const propPatches = {};
  const allKeys = new Set([...Object.keys(oldNode.props||{}), ...Object.keys(newNode.props||{})]);
  allKeys.forEach(key => {
    if (oldNode.props?.[key] !== newNode.props?.[key])
      propPatches[key] = newNode.props?.[key];
  });
  const childPatches = [];
  const maxLen = Math.max((oldNode.children||[]).length, (newNode.children||[]).length);
  for (let i = 0; i < maxLen; i++)
    childPatches.push(diff(oldNode.children?.[i], newNode.children?.[i]));
  return { type: 'UPDATE', propPatches, childPatches };
}

